from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a celestial body into a single fluent sentence.
    The function assumes all triples refer to the same subject (the celestial body).
    """
    if not triples:
        return ""

    subject = triples[0].subject

    # Helper to choose “a” or “an” based on the first letter
    def article(word: str) -> str:
        return "an" if word and word[0].lower() in "aeiou" else "a"

    # Mapping of predicates to natural‑language phrasing
    def phrase_for(triple: Triple) -> str:
        p = triple.predicate
        o = triple.object

        # Direct‑verb constructions
        if p == "discoverer":
            return f"was discovered by {o}"
        if p == "discovered":
            return f"was discovered on {o}"
        if p == "deathDate":
            return f"died on {o}"
        if p == "birthDate":
            return f"was born on {o}"
        if p == "deathPlace":
            return f"died in {o}"
        if p == "birthPlace":
            return f"was born in {o}"
        if p in {"nationality", "stateOfOrigin"}:
            return f"is {article(o)} {o}"
        if p == "formerName":
            return f"formerly known as {o}"
        if p == "absoluteMagnitude":
            return f"has an absolute magnitude of {o}"
        if p == "surfaceArea":
            return f"has a surface area of {o}"
        if p == "deathCause":
            return f"died from {o}"
        if p == "almaMater":
            return f"studied at {o}"
        if p == "doctoralStudent":
            return f"supervised doctoral student {o}"
        if p == "mass":
            return f"has a mass of {o}"
        if p == "density":
            return f"has a density of {o}"
        if p == "temperature":
            return f"has a temperature of {o}"
        if p == "maximumTemperature":
            return f"has a maximum temperature of {o}"
        if p == "minimumTemperature":
            return f"has a minimum temperature of {o}"
        if p == "meanTemperature":
            return f"has a mean temperature of {o}"
        if p == "averageSpeed":
            return f"has an average speed of {o}"
        if p == "escapeVelocity":
            return f"has an escape velocity of {o}"
        if p == "rotationPeriod":
            return f"rotates once every {o}"
        if p == "orbitalPeriod":
            return f"orbits in {o}"
        if p == "apoapsis":
            return f"has an apoapsis of {o}"
        if p == "periapsis":
            return f"has a periapsis of {o}"
        if p == "epoch":
            return f"has an epoch of {o}"
        # Fallback generic phrasing
        return f"{article(p)} {p} of {o}"

    # Build phrases for each triple
    phrases = [phrase_for(t) for t in triples]

    # Combine phrases into a single sentence
    if len(phrases) == 1:
        body = phrases[0]
    else:
        body = ", ".join(phrases[:-1]) + ", and " + phrases[-1]

    # Assemble the final sentence without adding an extra “has”
    return f"{subject} {body}."

